import { test, expect } from '@playwright/test';

test('create item via API then verify in UI', async ({ request, page }) => {
  // 1. Create item through the API
  const response = await request.post('/api/items', {
    data: { name: 'Widget', price: 9.99 },
  });
  expect(response.status()).toBe(201);

  const body = await response.json() as { id: number; name: string };
  expect(body.name).toBe('Widget');

  // 2. Verify the item appears in the browser UI
  await page.goto('/items');
  await expect(page.getByRole('listitem').filter({ hasText: 'Widget' })).toBeVisible();
});

