import { expect, APIResponse } from '@playwright/test';

type UserResponse = {
  id: number;
  email: string;
  role: string;
};

async function assertUserResponse(response: APIResponse): Promise<void> {
  expect(response.status()).toBe(200);

  const body = await response.json() as UserResponse;

  expect(typeof body.id).toBe('number');
  expect(typeof body.email).toBe('string');
  expect(typeof body.role).toBe('string');
  expect(body.email).toMatch(/.+@.+/);
}

import { test, expect } from '@playwright/test';
import path from 'path';

test('dashboard heading visible', async ({ context, page }, testInfo) => {
  await context.tracing.start({ screenshots: true, snapshots: true });

  await page.goto('/dashboard');
  await expect(page.getByRole('heading', { level: 1 })).toBeVisible();

  if (testInfo.status !== testInfo.expectedStatus) {
    const tracePath = path.join(testInfo.outputDir, 'trace.zip');
    await context.tracing.stop({ path: tracePath });
    await testInfo.attach('trace', { path: tracePath, contentType: 'application/zip' });
  } else {
    await context.tracing.stop();
  }
});

